// ==============================================================
// WF3 — Validar e preparar (monday)
// Lê o item encontrado, valida o payload e calcula:
//   - estado novo (concluido) e timestamps
//   - agregados (qtd_faltas, qtd_atrasos, total_minutos_atraso)
//   - flag editado se já estava concluido OU eh_correcao=true
// Saída: column_values_json para o change_multiple no item.
// ==============================================================

const COL_UUID         = 'text_mm2xjend';
const COL_PROTOCOLO    = 'text_mm2xsvg6';
const COL_DATA_INICIO  = 'date_mm2xtp93';
const COL_DATA_FIM     = 'date_mm2xrr5q';
const COL_EXPIRA_EM    = 'date_mm2xrvt4';
const COL_CONCLUIDO_EM = 'date_mm2xh1vm';
const COL_EDITADO_EM   = 'date_mm2x62fq';
const COL_STATUS       = 'color_mm2xkqpc';
const COL_EDITADO      = 'boolean_mm2x1aa4';
const COL_QTD_FALTAS   = 'numeric_mm2xe2zk';
const COL_QTD_ATRASOS  = 'numeric_mm2x18hh';
const COL_TOTAL_MIN    = 'numeric_mm2x4fjj';
const COL_DIAS_EXTRAS  = 'long_text_mm2x73w6';
const COL_DIAS_DESATIV = 'long_text_mm2xm820';
const COL_RESPOSTAS    = 'long_text_mm2xtcpw';
const COL_TOTAL_MIN_DEVIDOS = 'numeric_mm3455ss';
const COL_DIAS_PERDE_VT     = 'numeric_mm345xb6';
const COL_DIAS_PERDE_VR     = 'numeric_mm34a3ph';

const webhook = $('Webhook').first().json;
const body = webhook.body || {};
const uuid = webhook.query?.uuid || body.uuid;
const respostas = Array.isArray(body.respostas) ? body.respostas : [];
const protocolo = body.protocolo || null;
const diasExtras = Array.isArray(body.dias_extras) ? body.dias_extras : [];
const diasDesativ = Array.isArray(body.dias_desativados) ? body.dias_desativados : [];
const ehCorrecaoFlag = !!body.eh_correcao;

const all = $input.all();
function firstRealItem() {
  for (const it of all) {
    const j = it.json;
    if (j && j.id && (j.column_values || j.name)) return j;
  }
  return null;
}
const item = firstRealItem();

if (!item) {
  return [{ json: { _statusCode: 404, _erro: 'nao_encontrado', mensagem: 'Processamento não encontrado.' } }];
}

const columnValues = item.column_values ?? [];
const getCol = (id) => columnValues.find(c => c.id === id);
const text = (id) => getCol(id)?.text ?? null;
const rawValue = (id) => getCol(id)?.value ?? null;

function parseCheckbox(id) {
  const v = rawValue(id);
  if (!v) return false;
  try {
    const parsed = typeof v === 'string' ? JSON.parse(v) : v;
    return parsed?.checked === true || parsed?.checked === 'true';
  } catch { return false; }
}

const statusLabel = text(COL_STATUS);
const dataInicio  = text(COL_DATA_INICIO);
const dataFim     = text(COL_DATA_FIM);
const expiraEm    = text(COL_EXPIRA_EM);
const concluidoEmAtual = text(COL_CONCLUIDO_EM);
const jaEstavaEditado = parseCheckbox(COL_EDITADO);

const agora = new Date();

// 410 expirado
if (statusLabel === 'Expirado' || (expiraEm && agora > new Date(expiraEm + 'T23:59:59Z') && statusLabel !== 'Concluído')) {
  return [{ json: { _statusCode: 410, _erro: 'expirado', mensagem: 'Link expirado.' } }];
}

// 409 já concluído (se NÃO for correção)
if ((statusLabel === 'Concluído' || statusLabel === 'Concluido') && !ehCorrecaoFlag) {
  return [{ json: { _statusCode: 409, _erro: 'ja_concluido', mensagem: 'Este formulário já foi finalizado.' } }];
}

// Validar protocolo
if (!protocolo || !/^PROT-[A-Z0-9-]+$/i.test(protocolo)) {
  return [{ json: { _statusCode: 400, _erro: 'protocolo_invalido', mensagem: 'Protocolo ausente ou inválido.' } }];
}

// Conjunto de dias "válidos" = [periodo base] ∪ extras − desativados
const diasBase = [];
if (dataInicio && dataFim) {
  const cur = new Date(dataInicio + 'T00:00:00Z');
  const fim = new Date(dataFim + 'T00:00:00Z');
  while (cur <= fim) {
    diasBase.push(cur.toISOString().slice(0, 10));
    cur.setUTCDate(cur.getUTCDate() + 1);
  }
}
const desativ = new Set(diasDesativ);
const diasValidos = [...new Set([...diasBase, ...diasExtras])].filter(d => !desativ.has(d)).sort();

// Validar respostas: 1 por dia válido
const mapaRespostas = new Map(respostas.map(r => [r.data, r]));
const respostasFinal = [];
for (const dia of diasValidos) {
  const r = mapaRespostas.get(dia);
  if (!r || !r.tipo) {
    return [{ json: { _statusCode: 400, _erro: 'resposta_faltando', mensagem: `Resposta faltando para o dia ${dia}.` } }];
  }
  if (!['sem_ocorrencia','falta','atraso'].includes(r.tipo)) {
    return [{ json: { _statusCode: 400, _erro: 'tipo_invalido', mensagem: `Tipo inválido em ${dia}: ${r.tipo}` } }];
  }
  const minutos = r.minutos_atraso;
  if (r.tipo === 'atraso' && (!Number.isInteger(minutos) || minutos <= 0)) {
    return [{ json: { _statusCode: 400, _erro: 'minutos_invalidos', mensagem: `Minutos de atraso inválidos em ${dia}.` } }];
  }
  respostasFinal.push({
    data: dia,
    tipo: r.tipo,
    minutos_atraso: r.tipo === 'atraso' ? minutos : null
  });
}

// Agregados
const qtdFaltas  = respostasFinal.filter(r => r.tipo === 'falta').length;
const qtdAtrasos = respostasFinal.filter(r => r.tipo === 'atraso').length;
const totalMin   = respostasFinal.reduce((acc, r) => acc + (r.tipo === 'atraso' ? (r.minutos_atraso || 0) : 0), 0);

// Tempo devido + dias perde VT/VR (regra: jornada seg-sex=480min, sab=240min, dom=0;
// VT perde em falta+desconsid (qualquer dia util); VR perde em falta+desconsid+atraso seg-sex)
function _dow(d) { return new Date(d + 'T00:00:00Z').getUTCDay(); }
function _jornadaMin(d) { const x = _dow(d); if (x === 0) return 0; if (x === 6) return 240; return 480; }
function _isSabado(d) { return _dow(d) === 6; }
function _isDomingo(d) { return _dow(d) === 0; }

let totalMinDevidos = 0;
let diasPerdeVT = 0;
let diasPerdeVR = 0;

for (const d of diasDesativ) {
  if (_isDomingo(d)) continue;
  totalMinDevidos += _jornadaMin(d);
  diasPerdeVT += 1;
  if (!_isSabado(d)) diasPerdeVR += 1;
}
for (const r of respostasFinal) {
  if (_isDomingo(r.data)) continue;
  if (r.tipo === 'falta') {
    totalMinDevidos += _jornadaMin(r.data);
    diasPerdeVT += 1;
    if (!_isSabado(r.data)) diasPerdeVR += 1;
  } else if (r.tipo === 'atraso') {
    totalMinDevidos += r.minutos_atraso || 0;
    if (!_isSabado(r.data)) diasPerdeVR += 1;
  }
}

// Flag editado: se já estava concluído OU body.eh_correcao
const ehReedicao = (statusLabel === 'Concluído' || statusLabel === 'Concluido') || ehCorrecaoFlag;
const editadoFlag = ehReedicao || jaEstavaEditado;

function dateValue(d, withTime) {
  if (!d) return null;
  const x = d instanceof Date ? d : new Date(d);
  if (Number.isNaN(x.getTime())) return null;
  const yyyy = x.getUTCFullYear();
  const mm = String(x.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(x.getUTCDate()).padStart(2, '0');
  if (!withTime) return { date: `${yyyy}-${mm}-${dd}` };
  const hh = String(x.getUTCHours()).padStart(2, '0');
  const mi = String(x.getUTCMinutes()).padStart(2, '0');
  const ss = String(x.getUTCSeconds()).padStart(2, '0');
  return { date: `${yyyy}-${mm}-${dd}`, time: `${hh}:${mi}:${ss}` };
}

// Concluido_em: preserva se já existia
const concluidoEmFinal = concluidoEmAtual || `${agora.toISOString().slice(0, 19).replace('T', ' ')}`;

const columnValuesUpdate = {
  [COL_STATUS]:        { label: 'Concluído' },
  [COL_PROTOCOLO]:     protocolo,
  [COL_CONCLUIDO_EM]:  dateValue(concluidoEmAtual ? concluidoEmAtual : agora.toISOString(), true),
  [COL_EDITADO]:       { checked: editadoFlag ? 'true' : 'false' },
  [COL_EDITADO_EM]:    ehReedicao ? dateValue(agora.toISOString(), true) : null,
  [COL_QTD_FALTAS]:    String(qtdFaltas),
  [COL_QTD_ATRASOS]:   String(qtdAtrasos),
  [COL_TOTAL_MIN]:     String(totalMin),
  [COL_TOTAL_MIN_DEVIDOS]: String(totalMinDevidos),
  [COL_DIAS_PERDE_VT]:     String(diasPerdeVT),
  [COL_DIAS_PERDE_VR]:     String(diasPerdeVR),
  [COL_DIAS_EXTRAS]:   { text: JSON.stringify(diasExtras) },
  [COL_DIAS_DESATIV]:  { text: JSON.stringify(diasDesativ) },
  [COL_RESPOSTAS]:     { text: JSON.stringify(respostasFinal) }
};

// Remover chaves null para não sobrescrever data com vazio (caso ehReedicao=false)
for (const k of Object.keys(columnValuesUpdate)) {
  if (columnValuesUpdate[k] === null || columnValuesUpdate[k] === undefined) {
    delete columnValuesUpdate[k];
  }
}

return [{
  json: {
    _statusCode: 200,
    item_id: String(item.id),
    uuid,
    protocolo,
    editado: editadoFlag,
    eh_reedicao: ehReedicao,
    concluido_em_final: concluidoEmFinal,
    column_values_json: JSON.stringify(columnValuesUpdate)
  }
}];
